{
  "summary": "This paper presents a comprehensive empirical study evaluating the continual learning performance of five representative pre-trained language models (PLMs) combined with various continual learning (CL) methods across multiple NLP tasks and settings. It reveals that catastrophic forgetting is a significant challenge for PLMs, with rehearsal-based methods like experience replay being the most effective mitigation strategy, and provides novel layer-wise probing insights into the internal dynamics of forgetting.",
  "strengths": [
    {
      "point": "Comprehensive benchmark and systematic comparison",
      "evidence": "The study evaluates five PLMs, six CL methods spanning four categories, two incremental learning settings, and three diverse datasets, providing a broad and rigorous empirical foundation."
    },
    {
      "point": "Novel layer-wise probing analysis",
      "evidence": "The introduction of a prototype-based layer-wise probing method offers detailed insights into how different layers of PLMs are affected by forgetting and how CL methods preserve representational ability."
    },
    {
      "point": "Clear identification of rehearsal-based methods as most effective",
      "evidence": "Experience replay methods (ER and DERPP) consistently outperform regularization and dynamic architecture methods in accuracy and backward transfer across datasets."
    },
    {
      "point": "Release of code and datasets",
      "evidence": "The authors commit to open-sourcing their resources, facilitating reproducibility and further research in continual learning for NLP."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of comparison with recent or advanced continual learning methods",
      "evidence": "The paper omits newer CL approaches such as parameter-efficient fine-tuning (e.g., adapters, LoRA) and meta-learning based methods, limiting novelty and completeness."
    },
    {
      "point": "Insufficient justification for selected PLMs",
      "evidence": "No rationale is provided for choosing the five PLMs over others like T5, ELECTRA, or larger decoder-only models, which may affect generalizability."
    },
    {
      "point": "Missing ablation studies on replay buffer size and sampling strategies",
      "evidence": "Experience replay methods are highlighted as effective, but the impact of buffer size and sampling methods is not analyzed."
    },
    {
      "point": "Limited evaluation metrics and lack of statistical significance testing",
      "evidence": "Metrics focus mainly on accuracy and transfer without reporting memory footprint, computational overhead, forgetting curves, or statistical tests to validate results."
    },
    {
      "point": "Reproducibility concerns due to missing hyperparameter and computational resource details",
      "evidence": "The paper lacks detailed hyperparameter tuning protocols and comprehensive computational cost metrics, hindering reproducibility."
    },
    {
      "point": "Clarity issues in defining key metrics and probing methodology",
      "evidence": "Forward and backward transfer metrics are ambiguously defined, and the prototype-based probing method is insufficiently explained."
    },
    {
      "point": "Limited scope regarding scalability, task-free settings, and dataset diversity",
      "evidence": "The study focuses on three relatively small, English classification datasets and does not address task-free or online CL scenarios, nor few-shot or low-resource conditions."
    },
    {
      "point": "No analysis of forgetting dynamics over time",
      "evidence": "The paper reports aggregate metrics after all tasks but does not analyze how forgetting evolves incrementally."
    },
    {
      "point": "Potentially unfair comparison with joint training baseline",
      "evidence": "It is unclear whether joint training has access to the same total data and training budget as CL methods, which may bias results."
    }
  ],
  "questions": [
    {
      "question": "How would recent parameter-efficient fine-tuning or meta-learning based continual learning methods compare to the evaluated approaches?",
      "motivation": "Inclusion of these methods could provide a more complete understanding of state-of-the-art CL performance in NLP."
    },
    {
      "question": "What is the impact of replay buffer size and sampling strategy on the effectiveness of experience replay methods?",
      "motivation": "These design choices can significantly influence performance and forgetting, and understanding them is crucial for practical deployment."
    },
    {
      "question": "How do the findings generalize to larger-scale, generative, multilingual, or low-resource NLP tasks?",
      "motivation": "Extending evaluation beyond small English classification datasets is necessary to assess real-world applicability."
    },
    {
      "question": "Can the prototype-based layer-wise probing method be more clearly defined and validated to enhance interpretability?",
      "motivation": "Better clarity would strengthen confidence in the insights about internal PLM dynamics during continual learning."
    },
    {
      "question": "How does catastrophic forgetting evolve over incremental learning steps rather than only at the end?",
      "motivation": "Time-series analysis could reveal finer-grained dynamics and inform improved mitigation strategies."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
